1	//! `chid` subcommand — print the short change ID of each commit in a
2	//! revision range, one per line (script-friendly output).
3	//!
4	//! - `ChidArgs`: clap surface; flattens
5	//!   `options_flags::common_args::CommonArgs`.
6	//! - `ChidParams`: clap-free; embeds `common::CommonParams`. Built
7	//!   via `TryFrom<&ChidArgs>` at the binary edge.
8	//! - `chid(&Context, &ChidParams)`: the op — `for_each_repo` + print
9	//!   `format_chid`.
10	
11	use clap::Args;
12	use jj_lib::repo::Repo;
13	use log::{debug, info};
14	
15	use crate::common::{self, CommonParams};
16	use crate::context::Context;
17	use crate::options_flags::common_args::CommonArgs;
18	use crate::subcommand::SubcommandRunner;
19	
20	/// CLI args for `chid` — just the shared read-only commit-query args.
21	#[derive(Args, Debug)]
22	pub struct ChidArgs {
23	    #[command(flatten)]
24	    pub common: CommonArgs,
25	}
26	
27	/// Clap-free params for `chid`; embeds resolved `CommonParams`.
28	///
29	/// Carries a `suppress_banner` flag (read off `-L` / `--no-label`
30	/// at the binary edge) so the trait's default `dispatch` can
31	/// query it through `SubcommandRunner::suppress_banner` without
32	/// re-touching clap.
33	#[derive(Debug)]
34	pub struct ChidParams {
35	    pub common: CommonParams,
36	    pub suppress_banner: bool,
37	}
38	
39	impl TryFrom<&ChidArgs> for ChidParams {
40	    type Error = String;
41	
42	    /// Resolve clap `ChidArgs` into `ChidParams` by delegating to
43	    /// `CommonParams::try_from` and copying the no-label flag
44	    /// into `suppress_banner`.
45	    fn try_from(a: &ChidArgs) -> Result<Self, String> {
46	        Ok(ChidParams {
47	            common: CommonParams::try_from(&a.common)?,
48	            suppress_banner: a.common.no_label,
49	        })
50	    }
51	}
52	
53	/// Print the short change ID of each commit in the resolved range.
54	///
55	/// `_ctx` is unused (chid has no user-config or `--log` consumer);
56	/// it's present for the uniform subcommand-layer signature.
57	pub fn chid(_ctx: &Context, params: &ChidParams) -> Result<(), Box<dyn std::error::Error>> {
58	    debug!("chid: enter");
59	    let c = &params.common;
60	    common::for_each_repo(&c.repos, &c.header, |workspace, repo| {
61	        let (ids, _) = common::collect_ids(
62	            workspace,
63	            repo,
64	            &c.spec.rev,
65	            c.spec.desc_count,
66	            c.spec.anc_count,
67	        )?;
68	        for commit_id in &ids {
69	            let commit = repo.store().get_commit(commit_id)?;
70	            info!("{}", common::format_chid(&commit));
71	        }
72	        Ok(())
73	    })?;
74	    debug!("chid: exit");
75	    Ok(())
76	}
77	
78	impl SubcommandRunner for ChidArgs {
79	    type Params = ChidParams;
80	
81	    /// Delegate to the existing `TryFrom<&ChidArgs>` impl above.
82	    fn to_params(&self) -> Result<Self::Params, String> {
83	        ChidParams::try_from(self)
84	    }
85	
86	    /// Run the existing `chid` op.
87	    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
88	        chid(ctx, params)
89	    }
90	
91	    /// Read the banner-suppression flag off `ChidParams` for
92	    /// `crate::sb_ide` (queried from the trait's default
93	    /// `dispatch`).
94	    fn suppress_banner(params: &Self::Params) -> bool {
95	        params.suppress_banner
96	    }
97	}
